-- ============================================
-- 1. CREAR BASE DE DATOS
-- ============================================
DROP DATABASE IF EXISTS transactions;
CREATE DATABASE transactions;
USE transactions;

-- ============================================
-- 2. CREAR TABLAS
-- ============================================

CREATE TABLE IF NOT EXISTS user (
    id INT PRIMARY KEY,
    name VARCHAR(100),
    surname VARCHAR(100),
    phone VARCHAR(50),
    email VARCHAR(100),
    birth_date DATE,
    country VARCHAR(100),
    city VARCHAR(15),
    postal_code VARCHAR(15),
    address VARCHAR(100),
    signup_date DATE,
    user_segment VARCHAR(50),
    income_band VARCHAR(15)
);

CREATE TABLE IF NOT EXISTS company (
    id VARCHAR(15) PRIMARY KEY,
    company_name VARCHAR(255),
    phone VARCHAR(15),
    email VARCHAR(100),
    country VARCHAR(100),
    website VARCHAR(255)
);

CREATE TABLE IF NOT EXISTS credit_card (
    id VARCHAR(15) PRIMARY KEY,
    iban VARCHAR(50),
    pan VARCHAR(20),
    pin VARCHAR(10),
    cvv VARCHAR(5),
    expiring_date VARCHAR(10)
);

CREATE TABLE IF NOT EXISTS transaction (
    id VARCHAR(255),
    credit_card_id VARCHAR(15),
    company_id VARCHAR(20),
    user_id INT,
    lat FLOAT,
    longitude FLOAT,
    timestamp TIMESTAMP,
    amount DECIMAL(10, 2),
    declined BOOLEAN,

    CONSTRAINT pk_transaction PRIMARY KEY (id),
    CONSTRAINT fk_transaction_credit_card FOREIGN KEY (credit_card_id) REFERENCES credit_card(id),
    CONSTRAINT fk_transaction_user FOREIGN KEY (user_id) REFERENCES user(id),
    CONSTRAINT fk_transaction_company FOREIGN KEY (company_id) REFERENCES company(id)
);

